/* selectPROG00100Lst */

SELECT PJT_NM
     , TASK_NO, TASK_JOB, NAVI_PATH, CODE_NM, BACKEND, BACKEND_STATUS_NM
     , BACKEND_STD_DT, BACKEND_END_DT, FRONTEND, RONTEND_STATUS_NM, FRONTEND_STD_DT, FRONTEND_END_DT
FROM TASK_EMP_STATUS
WHERE BACKEND_STATUS!='999999' OR FRONTEND_STATUS!='999999'
ORDER BY PJT_NM, SORT_PATH
LIMIT #{limit}
OFFSET #{offset}
